        const obvResult = calcOBV(closeD, volD, dIdx);
        if (obvResult.obvTrend === 1) {
          score += 20;
          signals.push('OBV수급확인');
        } else if (obvResult.obvTrend === -1) {
          score -= 10; // 수급 없는 상승 → 경고
          signals.push('OBV수급불일치');
        }

